#include <cstdarg>

// Variadic function definition - Noncompliant
void MyPrintf(const char* format, ...) {
    va_list args;
    va_start(args, format);
    // Process arguments
    va_end(args);
}

// Another variadic function example
int sum(int count, ...) { // Noncompliant
    va_list args;
    va_start(args, count);

    int total = 0;
    for (int i = 0; i < count; ++i) {
        total += va_arg(args, int);
    }

    va_end(args);
    return total;
}

