#include <vector>
#include <initializer_list>

// Use container for multiple arguments
int sum(const std::vector<int>& values) {
    int total = 0;
    for (int value : values) {
        total += value;
    }
    return total;
}

// Or use initializer list
int sum(std::initializer_list<int> values) {
    int total = 0;
    for (int value : values) {
        total += value;
    }
    return total;
}

// Usage: sum({1, 2, 3, 4, 5})
